/* syscall_dispatch: 系统调用分发器
 *   从 trapframe.a7 读取系统调用号，分发给对应实现函数
 *   返回值写入 trapframe.a0，并推进 epc 跳过 ecall 指令
 *   不返回的函数（exit/exec/shutdown）自行处理 epc
 *
 * fdget / fdput / fdnum: Linux 风格的 fd 生命周期配对
 *   fdget:  从 trapframe arg_n 读取 fd → 查表 → 递增 file 引用计数
 *   fdput:  释放 fdget 获取的引用
 *   fdnum:  仅提取 fd 号（用于 sys_close 等仅需 fd 号无需查表的场景）
 */
#include <syscall/syscall.h>
